mapper.sql:
where a.source_owner_type = #{sourceOwnerType}
  and a.source_owner_id = #{sourceOwnerId}

  and a.community_id = #{communityId}

mapper.select:
select a.*, u.nx_CU_user_id as invitee_nx_CU_user_id, u.nx_CU_wx_nick_name as invitee_nx_CU_wx_nick_name, u.nx_CU_wx_avatar_url as invitee_nx_CU_wx_avatar_url, u.nx_CU_wx_phone_number as invitee_nx_CU_wx_phone_number, u.nx_CU_join_date as invitee_nx_CU_join_date from nx_customer_promotion_code_attempt a left join nx_customer_user u on u.nx_CU_user_id = a.invitee_user_id
order by a.attempted_at desc, a.nx_customer_promotion_code_attempt_id desc
limit #{offset}, #{limit}

mapper.delete:
delete from nx_customer_promotion_code_attempt
where source_owner_type = #{sourceOwnerType}
  and source_owner_id = #{sourceOwnerId}
